13	
14	const PROCESSING_FEE = 5;
15	
16	export function quote(items: Item[]): number {
17	  if (items.length === 0) return 0;
18	  const basePremium = items.reduce(
19	    (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
20	    0
21	  );
22	  return basePremium + PROCESSING_FEE;
23	}
